72	function buildLabelLines(node: TraceNode): string[] {
73	  const lines: string[] = [];
74	
75	  switch (node.type) {
76	    case 'agent':
77	      lines.push('agent');
78	      if (node.user_id != null) lines.push(node.user_id);
79	      break;
80	    case 'session':
81	      lines.push('session');
82	      if (node.session_id != null) lines.push(node.session_id);
83	      break;
84	    case 'interaction':
85	      lines.push('interaction');
86	      if (node.prompt != null) lines.push(node.prompt.replace(/\s+/g, ' '));
87	      break;
88	    case 'llm_request':
89	      lines.push('llm_request');
90	      if (node.model != null) lines.push(`model: ${node.model}`);
91	      if (node.source != null) lines.push(`source: ${node.source}`);
92	      if (node.prompt != null) lines.push(node.prompt.replace(/\s+/g, ' '));
93	      if (node.response != null) lines.push(node.response.replace(/\s+/g, ' '));
94	      break;
95	    case 'tool':
96	      lines.push('tool');
97	      if (node.name != null) lines.push(`name: ${node.name}`);
98	      if (node.tool_input != null) lines.push(`input: ${node.tool_input}`);
99	      break;
100	    case 'tool.blocked_on_user':
101	      lines.push('blocked_on_user');
102	      break;
103	    case 'tool.execution':
104	      lines.push('execution');
105	      break;
106	    case 'hook':
107	      lines.push('hook');
108	      if (node.name != null) lines.push(`name: ${node.name}`);
109	      break;
110	    default:
111	      lines.push(node.type);
112	  }
113	
114	  if (node.duration_ms != null) lines.push(`duration: ${formatDuration(node.duration_ms)}`);
115	  if (node.tokens_in != null) lines.push(`tokens in: ${String(node.tokens_in)}`);
116	  if (node.tokens_out != null) lines.push(`tokens out: ${String(node.tokens_out)}`);
117	  if (node.cost_usd != null) lines.push(`cost: $${node.cost_usd.toFixed(6)}`);
118	
119	  return lines;
120	}
