126	function toViewNode(node: TraceNode, childrenOf: Map<string, TraceNode[]>): GraphViewNode {
127	  const rawChildren = childrenOf.get(node.id);
128	  const labelLines = buildLabelLines(node);
129	
130	  if (rawChildren == null || rawChildren.length === 0) {
131	    return { id: node.id, labelLines, children: [], innerEdges: [] };
132	  }
133	
134	  const sorted = sortByStart(rawChildren);
135	  const childNodes = sorted.map((child) => toViewNode(child, childrenOf));
136	
137	  const innerEdges: GraphViewEdge[] = [];
138	  for (let i = 0; i < childNodes.length - 1; i += 1) {
139	    const prev = childNodes[i];
140	    const next = childNodes[i + 1];
141	    if (prev == null || next == null) continue;
142	    // No gap labels inside subgraphs — labels mid-edge overlap the subgraph title text.
143	    innerEdges.push({ fromId: resolveId(prev), toId: resolveId(next) });
