149	// Assigns a non-llm_request node (tool or hook) to a thread.
150	// UserPromptSubmit always goes to repl_main_thread (it precedes the first LLM
151	// call and belongs to the main conversation thread by definition).
152	// All others: pick the thread whose llm_request ended most recently before this
153	// node started. Falls back to the thread with the earliest-starting llm_request
154	// for nodes that fire before any llm_request has ended.
155	function assignNodeToThread(
156	  node: TraceNode,
157	  llmsByThread: Map<string, TraceNode[]>,
158	): string | null {
159	  if (node.type === 'hook' && node.name === 'UserPromptSubmit') {
160	    return llmsByThread.has('repl_main_thread') ? 'repl_main_thread' : null;
161	  }
162	
163	  const nodeStart = node.start_time_ns != null ? BigInt(node.start_time_ns) : null;
164	
165	  // Priority 1: node fires while an llm_request span is still open — belongs to
166	  // that thread (e.g. PreToolUse hooks fire just before the LLM span closes).
167	  // Among overlapping spans, pick the one that started most recently.
168	  if (nodeStart != null) {
169	    let overlappingThread: string | null = null;
170	    let overlappingStart = -1n;
171	    for (const [source, reqs] of llmsByThread) {
172	      for (const req of reqs) {
173	        if (req.start_time_ns == null || req.end_time_ns == null) continue;
174	        const s = BigInt(req.start_time_ns);
175	        const e = BigInt(req.end_time_ns);
176	        if (s <= nodeStart && nodeStart <= e && s > overlappingStart) {
177	          overlappingStart = s;
178	          overlappingThread = source;
179	        }
180	      }
181	    }
182	    if (overlappingThread != null) return overlappingThread;
183	  }
184	
185	  // Priority 2: pick the thread whose llm_request ended most recently before this node.
186	  let bestByEnd: string | null = null;
187	  let bestEnd = -1n;
188	  let firstByStart: string | null = null;
189	  let firstStart = 99999999999999999999n;
190	
191	  for (const [source, reqs] of llmsByThread) {
192	    for (const req of reqs) {
193	      if (req.start_time_ns != null) {
194	        const s = BigInt(req.start_time_ns);
195	        if (s < firstStart) {
196	          firstStart = s;
197	          firstByStart = source;
198	        }
199	      }
200	      if (nodeStart != null && req.end_time_ns != null) {
201	        const e = BigInt(req.end_time_ns);
202	        if (e <= nodeStart && e > bestEnd) {
203	          bestEnd = e;
204	          bestByEnd = source;
205	        }
206	      }
207	    }
208	  }
209	
210	  return bestByEnd ?? firstByStart;
211	}
