213	function buildChildrenOf(nodes: readonly TraceNode[]): Map<string, TraceNode[]> {
214	  const byId = new Map(nodes.map((n) => [n.id, n]));
215	  const childrenOf = new Map<string, TraceNode[]>();
216	  for (const n of nodes) {
217	    if (n.parent != null && byId.has(n.parent)) {
218	      const list = childrenOf.get(n.parent) ?? [];
219	      list.push(n);
220	      childrenOf.set(n.parent, list);
221	    }
222	  }
223	  return childrenOf;
224	}
