226	export function buildCausalGraphView(nodes: readonly TraceNode[]): CausalGraphView | null {
227	  const childrenOf = buildChildrenOf(nodes);
228	
229	  const interaction = nodes.find((n) => n.type === 'interaction');
230	  if (interaction == null) return null;
231	
232	  const directChildren = childrenOf.get(interaction.id) ?? [];
233	
234	  const llmsByThread = new Map<string, TraceNode[]>();
235	  for (const n of directChildren) {
236	    if (n.type !== 'llm_request') continue;
237	    const src = n.source ?? 'unknown';
238	    const list = llmsByThread.get(src) ?? [];
239	    list.push(n);
240	    llmsByThread.set(src, list);
241	  }
242	
243	  const threadMembers = new Map<string, TraceNode[]>();
244	  for (const [src, reqs] of llmsByThread) {
245	    threadMembers.set(src, [...reqs]);
246	  }
247	  for (const n of directChildren) {
248	    if (n.type !== 'tool' && n.type !== 'hook') continue;
249	    const thread = assignNodeToThread(n, llmsByThread);
250	    if (thread != null) {
251	      threadMembers.get(thread)?.push(n);
252	    }
253	  }
254	
255	  for (const [src, members] of threadMembers) {
256	    threadMembers.set(src, sortByStart(members));
257	  }
258	
259	  const sortedSources = [...threadMembers.keys()].sort((a, b) => {
260	    const aFirst = threadMembers.get(a)?.[0];
261	    const bFirst = threadMembers.get(b)?.[0];
262	    return compareStart(aFirst ?? interaction, bFirst ?? interaction);
263	  });
264	
265	  const root: GraphViewNode = {
266	    id: interaction.id,
267	    labelLines: buildLabelLines(interaction),
268	    children: [],
269	    innerEdges: [],
270	  };
271	
272	  const threads: GraphViewThread[] = sortedSources.map((source) => {
273	    const members = threadMembers.get(source) ?? [];
274	    const threadId = `thread_${source.replace(/\W+/g, '_')}`;
275	    const memberViewNodes = members.map((m) => toViewNode(m, childrenOf));
276	
277	    const edges: GraphViewEdge[] = [];
278	    for (let i = 0; i < memberViewNodes.length - 1; i += 1) {
279	      const prevNode = members[i];
280	      const nextNode = members[i + 1];
281	      if (prevNode == null || nextNode == null) continue;
282	      const prevView = memberViewNodes[i];
283	      const nextView = memberViewNodes[i + 1];
284	      if (prevView == null || nextView == null) continue;
285	      const gap = formatGap(prevNode, nextNode);
286	      edges.push({
287	        fromId: resolveId(prevView),
288	        toId: resolveId(nextView),
289	        ...(gap !== null ? { label: gap } : {}),
290	      });
291	    }
292	
293	    return {
294	      id: threadId,
295	      title: `thread: ${source}`,
296	      members: memberViewNodes,
297	      edges,
298	    };
299	  });
300	
301	  return {
302	    root,
303	    threads,
304	    rootToThreadIds: threads.map((t) => t.id),
305	  };
306	}
307	
308	function nodeSubtree(nodes: readonly TraceNode[], rootId: string): TraceNode[] {
309	  const byId = new Map(nodes.map((n) => [n.id, n]));
310	  const childrenOf = buildChildrenOf(nodes);
311	  const result: TraceNode[] = [];
312	  const queue: string[] = [rootId];
313	  while (queue.length > 0) {
314	    const id = queue.shift();
315	    if (id == null) continue;
316	    const node = byId.get(id);
317	    if (node == null) continue;
318	    result.push(node);
319	    for (const child of childrenOf.get(id) ?? []) {
320	      queue.push(child.id);
321	    }
322	  }
323	  return result;
324	}
325	
326	export function buildSessionCausalGraphView(
327	  nodes: readonly TraceNode[],
328	): SessionCausalGraphView | null {
329	  const session = nodes.find((n) => n.type === 'session');
330	  if (session == null) return null;
331	
332	  const childrenOf = buildChildrenOf(nodes);
333	  const interactions = sortByStart(
334	    (childrenOf.get(session.id) ?? []).filter((n) => n.type === 'interaction'),
335	  );
336	  if (interactions.length === 0) return null;
337	
338	  const root: GraphViewNode = {
339	    id: session.id,
340	    labelLines: buildLabelLines(session),
341	    children: [],
342	    innerEdges: [],
343	  };
344	
345	  const interactionViews = interactions.map((interaction, i) => {
346	    const title =
347	      interaction.prompt != null
348	        ? truncate(interaction.prompt.replace(/\s+/g, ' '), 60)
349	        : `interaction ${String(i + 1)}`;
350	    const interactionNodes = nodeSubtree(nodes, interaction.id);
351	    const view = buildCausalGraphView(interactionNodes) ?? {
352	      root: {
353	        id: interaction.id,
354	        labelLines: buildLabelLines(interaction),
355	        children: [],
356	        innerEdges: [],
357	      },
358	      threads: [],
359	      rootToThreadIds: [],
360	    };
361	    return { title, view };
362	  });
363	
364	  return { root, interactions: interactionViews };
365	}
366	
367	export function buildAgentCausalGraphView(
368	  nodes: readonly TraceNode[],
369	): AgentCausalGraphView | null {
370	  const agent = nodes.find((n) => n.type === 'agent');
371	  if (agent == null) return null;
372	
373	  const childrenOf = buildChildrenOf(nodes);
374	  const sessions = sortByStart(
375	    (childrenOf.get(agent.id) ?? []).filter((n) => n.type === 'session'),
376	  );
377	  if (sessions.length === 0) return null;
378	
379	  const root: GraphViewNode = {
380	    id: agent.id,
381	    labelLines: buildLabelLines(agent),
382	    children: [],
383	    innerEdges: [],
384	  };
385	
386	  const sessionViews = sessions.map((session, i) => {
387	    const title =
388	      session.session_id != null ? truncate(session.session_id, 40) : `session ${String(i + 1)}`;
389	    const sessionNodes = nodeSubtree(nodes, session.id);
390	    const view = buildSessionCausalGraphView(sessionNodes) ?? {
391	      root: { id: session.id, labelLines: buildLabelLines(session), children: [], innerEdges: [] },
392	      interactions: [],
393	    };
394	    return { title, view };
395	  });
396	
397	  return { root, sessions: sessionViews };
398	}
