1	import { Buffer } from 'node:buffer';
2	import { createHash } from 'node:crypto';
3	import type { LogEntry, OtlpAttribute, OtlpBatch, OtlpSpan, TempoTrace } from './types.ts';
4	
5	// ── ID helpers ────────────────────────────────────────────────────────────────
6	
7	function b64toHex(b64: string): string {
8	  return Buffer.from(b64, 'base64').toString('hex');
9	}
10	
11	// Deterministic 8-byte span ID for synthetic hook spans
12	function hookSpanB64(index: number): string {
13	  const hash = createHash('sha256')
14	    .update(`coach-hook-span-${String(index)}`)
15	    .digest();
16	  return hash.subarray(0, 8).toString('base64');
17	}
18	
19	// ── Attribute helpers ─────────────────────────────────────────────────────────
20	
21	function strAttr(key: string, value: string): OtlpAttribute {
22	  return { key, value: { stringValue: value } };
23	}
24	
25	function getStringAttr(attrs: readonly OtlpAttribute[], key: string): string | null {
26	  const a = attrs.find((x) => x.key === key);
27	  if (!a) return null;
28	  return 'stringValue' in a.value ? a.value.stringValue : null;
29	}
30	
31	// ── Log utilities (same attribution logic as transform.ts) ───────────────────
32	
33	interface SpanMeta {
34	  readonly id: string; // 's' + hex
35	  readonly b64: string;
36	  readonly parentB64: string | null;
37	  readonly startNs: bigint;
38	  readonly endNs: bigint;
39	  readonly spanType: string;
40	  readonly toolName: string | null;
41	  readonly requestId: string | null;
42	}
43	
44	function collectSpanMeta(trace: TempoTrace): SpanMeta[] {
45	  const metas: SpanMeta[] = [];
46	  for (const batch of trace.batches) {
47	    for (const ss of batch.scopeSpans) {
48	      for (const span of ss.spans) {
49	        const spanType = getStringAttr(span.attributes, 'span.type') ?? span.name;
50	        metas.push({
51	          id: 's' + b64toHex(span.spanId),
52	          b64: span.spanId,
53	          parentB64: span.parentSpanId ?? null,
54	          startNs: BigInt(span.startTimeUnixNano),
55	          endNs: BigInt(span.endTimeUnixNano),
56	          spanType,
57	          toolName: getStringAttr(span.attributes, 'tool_name'),
58	          requestId: getStringAttr(span.attributes, 'request_id'),
59	        });
60	      }
61	    }
62	  }
63	  metas.sort((a, b) => (a.startNs < b.startNs ? -1 : a.startNs > b.startNs ? 1 : 0));
64	  return metas;
65	}
66	
67	function narrowestContaining(metas: readonly SpanMeta[], ns: bigint): SpanMeta | null {
68	  let best: SpanMeta | null = null;
69	  let bestDur = BigInt(-1);
70	  for (const m of metas) {
71	    if (ns >= m.startNs && ns <= m.endNs) {
72	      const dur = m.endNs - m.startNs;
73	      if (best === null || dur < bestDur) {
74	        best = m;
75	        bestDur = dur;
76	      }
77	    }
78	  }
79	  return best;
80	}
81	
82	function lastEndedBefore(metas: readonly SpanMeta[], ns: bigint): SpanMeta | null {
83	  let best: SpanMeta | null = null;
84	  for (const m of metas) {
85	    if (m.endNs <= ns && (best === null || m.endNs > best.endNs)) best = m;
86	  }
87	  return best;
88	}
89	
90	function attributeLogsToSpans(
91	  metas: readonly SpanMeta[],
92	  logs: readonly LogEntry[],
93	): Map<string, LogEntry[]> {
94	  const requestIdIndex = new Map<string, string>();
95	  const childIds = new Set<string>();
96	  for (const m of metas) {
97	    if (m.requestId !== null) requestIdIndex.set(m.requestId, m.id);
98	    if (m.parentB64 !== null) childIds.add(m.id);
99	  }
100	
101	  const sorted = [...logs].sort(
102	    (a, b) => parseInt(a.event_sequence, 10) - parseInt(b.event_sequence, 10),
103	  );
104	
105	  const bySpan = new Map<string, LogEntry[]>();
106	  for (const log of sorted) {
107	    let target: string;
108	    if (log.request_id != null) {
109	      target = requestIdIndex.get(log.request_id) ?? log.span_id;
110	    } else if (childIds.has(log.span_id)) {
111	      target = log.span_id;
112	    } else {
113	      const m = narrowestContaining(metas, BigInt(log.timestamp_ns));
114	      target = m !== null ? m.id : log.span_id;
115	    }
116	    const bucket = bySpan.get(target);
117	    if (bucket !== undefined) bucket.push(log);
118	    else bySpan.set(target, [log]);
119	  }
120	
121	  return bySpan;
122	}
123	
124	// ── Request body index ────────────────────────────────────────────────────────
125	
126	// api_request_body logs lack request_id; pair them positionally with
127	// api_response_body logs (both ordered by event_sequence) to get a
128	// request_id → raw_request_body map that works even when timestamps
129	// place the request log outside the span's time window.
130	function buildRequestBodyIndex(logs: readonly LogEntry[]): Map<string, string> {
131	  const sorted = [...logs].sort(
132	    (a, b) => parseInt(a.event_sequence, 10) - parseInt(b.event_sequence, 10),
133	  );
134	  const requestBodies = sorted.filter((l) => l.event_name === 'api_request_body' && l.body != null);
135	  const responseBodies = sorted.filter(
136	    (l) => l.event_name === 'api_response_body' && l.request_id != null,
137	  );
138	  const index = new Map<string, string>();
139	  for (let i = 0; i < requestBodies.length && i < responseBodies.length; i++) {
140	    const reqId = responseBodies[i]?.request_id;
141	    const body = requestBodies[i]?.body;
142	    if (reqId != null && body != null) index.set(reqId, body);
143	  }
144	  return index;
145	}
146	
147	// ── Tool input lookup ─────────────────────────────────────────────────────────
148	
149	function buildToolInputIndex(
150	  metas: readonly SpanMeta[],
151	  allLogs: readonly LogEntry[],
152	  logsBySpan: Map<string, LogEntry[]>,
153	): Map<string, string> {
154	  const useIdToInput = new Map<string, string>();
155	  for (const log of allLogs) {
156	    if (log.tool_use_id != null && log.tool_input != null) {
157	      useIdToInput.set(log.tool_use_id, log.tool_input);
158	    }
159	  }
160	
161	  const result = new Map<string, string>();
162	  for (const m of metas) {
163	    if (m.spanType !== 'tool.blocked_on_user' || m.parentB64 === null) continue;
164	    const parentId = 's' + b64toHex(m.parentB64);
165	    const logs = logsBySpan.get(m.id) ?? [];
166	    const decision = logs.find((l) => l.tool_use_id != null);
167	    if (decision?.tool_use_id == null) continue;
168	    const input = useIdToInput.get(decision.tool_use_id);
169	    if (input != null) result.set(parentId, input);
170	  }
171	
172	  return result;
173	}
174	
175	function summarizeToolInput(json: string, max = 120): string | null {
176	  try {
177	    const parsed = JSON.parse(json) as Record<string, unknown>;
178	    const useful = parsed.command ?? parsed.file_path ?? parsed.skill ?? parsed.query;
179	    if (typeof useful === 'string' || typeof useful === 'number' || typeof useful === 'boolean') {
180	      return String(useful).slice(0, max);
181	    }
182	    for (const v of Object.values(parsed)) {
183	      if (typeof v === 'string' && v.length > 0) return v.slice(0, max);
184	    }
185	    return null;
186	  } catch {
187	    return json.slice(0, max);
188	  }
189	}
190	
191	// ── Hook span construction ────────────────────────────────────────────────────
192	
193	interface HookEntry {
194	  readonly index: number;
195	  readonly hookName: string;
196	  readonly startNs: bigint;
197	  readonly endNs: bigint;
198	  readonly durationMs: number | null;
199	}
200	
201	function extractHooks(logs: readonly LogEntry[]): HookEntry[] {
202	  const sorted = [...logs].sort(
203	    (a, b) => parseInt(a.event_sequence, 10) - parseInt(b.event_sequence, 10),
204	  );
205	
206	  // Map hook_name → ordered list of complete timestamps
207	  const completesByName = new Map<string, bigint[]>();
208	  for (const log of sorted) {
209	    if (log.event_name === 'hook_execution_complete' && log.hook_name != null) {
210	      const list = completesByName.get(log.hook_name) ?? [];
211	      list.push(BigInt(log.timestamp_ns));
212	      completesByName.set(log.hook_name, list);
213	    }
214	  }
215	
216	  const startCountByName = new Map<string, number>();
217	  const hooks: HookEntry[] = [];
218	  let index = 0;
219	
220	  for (const log of sorted) {
221	    if (log.event_name !== 'hook_execution_start' || log.hook_name == null) continue;
222	    const count = startCountByName.get(log.hook_name) ?? 0;
223	    startCountByName.set(log.hook_name, count + 1);
224	
225	    const startNs = BigInt(log.timestamp_ns);
226	    const endNs = completesByName.get(log.hook_name)?.[count] ?? startNs;
227	    const durationMs = log.total_duration_ms != null ? Number(log.total_duration_ms) || null : null;
228	
229	    hooks.push({ index: index++, hookName: log.hook_name, startNs, endNs, durationMs });
230	  }
231	
232	  return hooks;
233	}
234	
235	function parseHookEvent(hookName: string): { event: string; toolName: string | null } {
236	  const i = hookName.indexOf(':');
237	  if (i === -1) return { event: hookName, toolName: null };
238	  return { event: hookName.slice(0, i), toolName: hookName.slice(i + 1) || null };
239	}
240	
241	const INTERACTION_LEVEL_HOOKS = new Set([
242	  'UserPromptSubmit',
243	  'UserPromptExpansion',
244	  'Stop',
245	  'StopFailure',
246	  'SubagentStop',
247	  'SubagentStart',
248	]);
249	
250	function resolveHookParentB64(metas: readonly SpanMeta[], hook: HookEntry): string | null {
251	  const { event, toolName } = parseHookEvent(hook.hookName);
252	
253	  if (event === 'PreToolUse' && toolName != null) {
254	    const match = metas
255	      .filter((m) => m.spanType === 'tool' && m.toolName === toolName && m.startNs >= hook.startNs)
256	      .sort((a, b) => (a.startNs < b.startNs ? -1 : 1))[0];
257	    if (match) return match.b64;
258	  }
259	
260	  if (event === 'PostToolUse' && toolName != null) {
261	    const match = metas
262	      .filter((m) => m.spanType === 'tool' && m.toolName === toolName && m.endNs <= hook.startNs)
263	      .sort((a, b) => (a.endNs > b.endNs ? -1 : 1))[0];
264	    if (match) return match.b64;
265	  }
266	
267	  if (INTERACTION_LEVEL_HOOKS.has(event)) {
268	    return metas.find((m) => m.spanType === 'interaction')?.b64 ?? null;
269	  }
270	
271	  return (
272	    (lastEndedBefore(metas, hook.startNs) ?? narrowestContaining(metas, hook.startNs))?.b64 ?? null
273	  );
274	}
275	
276	// ── Span enrichment ───────────────────────────────────────────────────────────
277	
278	function enrichSpan(
279	  span: OtlpSpan,
280	  meta: SpanMeta,
281	  logs: LogEntry[],
282	  toolInput: string | null,
283	  requestBodyIndex: Map<string, string>,
284	): OtlpSpan {
285	  const extra: OtlpAttribute[] = [];
286	  const spanType = meta.spanType;
287	
288	  if (spanType === 'llm_request') {
289	    const apiLog = logs.find((l) => l.event_name === 'api_request');
290	    const responseLog = logs.find((l) => l.event_name === 'api_response_body' && l.body != null);
291	
292	    // Prefer the positional index (reliable even when the log timestamp falls
293	    // outside the span's window); fall back to the attributed log.
294	    const rawRequestBody =
295	      (meta.requestId != null ? requestBodyIndex.get(meta.requestId) : undefined) ??
296	      logs.find((l) => l.event_name === 'api_request_body' && l.body != null)?.body ??
297	      null;
298	
299	    if (apiLog?.query_source != null) extra.push(strAttr('query_source', apiLog.query_source));
300	    if (apiLog?.cost_usd != null) extra.push(strAttr('cost_usd', apiLog.cost_usd));
301	    if (rawRequestBody != null) extra.push(strAttr('raw_request_body', rawRequestBody));
302	    if (responseLog?.body != null) extra.push(strAttr('raw_response_body', responseLog.body));
303	  }
304	
305	  if (spanType === 'tool' && toolInput != null) {
306	    const summary = summarizeToolInput(toolInput);
307	    if (summary != null) extra.push(strAttr('tool_input_summary', summary));
308	  }
309	
310	  return extra.length > 0 ? { ...span, attributes: [...span.attributes, ...extra] } : span;
311	}
312	
313	// ── Public API ────────────────────────────────────────────────────────────────
314	
315	function getTraceId(trace: TempoTrace): string {
316	  for (const batch of trace.batches) {
317	    for (const ss of batch.scopeSpans) {
318	      for (const span of ss.spans) {
319	        return span.traceId;
320	      }
321	    }
322	  }
323	  return '';
324	}
325	
326	export function enrichTrace(trace: TempoTrace, logs: readonly LogEntry[]): TempoTrace {
327	  const traceId = getTraceId(trace);
328	  const metas = collectSpanMeta(trace);
329	  const logsBySpan = attributeLogsToSpans(metas, logs);
330	  const toolInputBySpanId = buildToolInputIndex(metas, logs, logsBySpan);
331	  const requestBodyIndex = buildRequestBodyIndex(logs);
332	  const hooks = extractHooks(logs);
333	
334	  // Build enriched span batches
335	  const enrichedBatches: OtlpBatch[] = trace.batches.map((batch) => ({
336	    ...batch,
337	    scopeSpans: batch.scopeSpans.map((ss) => ({
338	      ...ss,
339	      spans: ss.spans.map((span) => {
340	        const meta = metas.find((m) => m.b64 === span.spanId);
341	        if (meta == null) return span;
342	        const spanLogs = logsBySpan.get(meta.id) ?? [];
343	        const toolInput = toolInputBySpanId.get(meta.id) ?? null;
344	        return enrichSpan(span, meta, spanLogs, toolInput, requestBodyIndex);
345	      }),
346	    })),
347	  }));
348	
349	  // Build hook spans
350	  const hookSpans: OtlpSpan[] = hooks.map((hook) => {
351	    const hookB64 = hookSpanB64(hook.index);
352	    const parentB64 = resolveHookParentB64(metas, hook);
353	
354	    const span: OtlpSpan = {
355	      traceId,
356	      spanId: hookB64,
357	      name: 'claude_code.hook',
358	      startTimeUnixNano: String(hook.startNs),
359	      endTimeUnixNano: String(hook.endNs),
360	      attributes: [
361	        strAttr('span.type', 'hook'),
362	        strAttr('hook.name', hook.hookName),
363	        ...(hook.durationMs != null ? [strAttr('duration_ms', String(hook.durationMs))] : []),
364	      ],
365	    };
366	
367	    if (parentB64) return { ...span, parentSpanId: parentB64 };
368	    return span;
369	  });
370	
371	  if (hookSpans.length === 0) return { batches: enrichedBatches };
372	
373	  // Append hook spans into the first existing scopeSpan to preserve its scope metadata
374	  if (enrichedBatches.length === 0) return { batches: [] };
375	  const [first, ...rest] = enrichedBatches as [OtlpBatch, ...OtlpBatch[]];
376	  const [firstScope, ...otherScopes] = first.scopeSpans as [
377	    { spans: readonly OtlpSpan[] },
378	    ...{ spans: readonly OtlpSpan[] }[],
379	  ];
380	  const enrichedFirst: OtlpBatch = {
381	    ...first,
382	    scopeSpans: [{ ...firstScope, spans: [...firstScope.spans, ...hookSpans] }, ...otherScopes],
383	  };
384	
385	  return { batches: [enrichedFirst, ...rest] };
386	}
