16	  if (typeof content === 'string') return content;
17	  for (const b of content) {
18	    if (b.type === 'text' && b.text) return b.text;
19	  }
20	  return null;
21	}
22	
23	function unescape(s: string): string {
24	  return s
25	    .replace(/\\"/g, '"')
26	    .replace(/\\n/g, '\n')
27	    .replace(/\\r/g, '\r')
28	    .replace(/\\t/g, '\t')
29	    .replace(/\\\\/g, '\\');
30	}
31	
32	function extractRequestPrompt(bodyJson: string): string | null {
33	  try {
34	    const parsed = JSON.parse(bodyJson) as ReqBody;
35	    const messages = parsed.messages ?? [];
36	    for (let i = messages.length - 1; i >= 0; i--) {
37	      const msg = messages[i];
38	      if (msg?.role !== 'user') continue;
39	      const text = firstText(msg.content);
40	      if (text) return text.trim();
41	    }
42	    return null;
43	  } catch {
44	    let lastIdx = -1;
